import React from "react";
import img1 from "./../../image/1.jpg";
import img2 from "./../../image/2.jpg";
import img3 from "./../../image/3.jpg";

function Carousel() {
  return (
    <div className="d-flex justify-content-center my-5">
      <div id="carouselExampleControls" className="carousel slide custom-carousel">
        <div className="carousel-inner rounded shadow">
          <div className="carousel-item active">
            <img src={require("../../../image/2.jpg").default} className="d-block w-100 carousel-img" alt="Slide 1" />
          </div>
          <div className="carousel-item">
            <img src={require("../../../image/1.jpg").default} className="d-block w-100 carousel-img" alt="Slide 2" />
          </div>
          <div className="carousel-item">
            <img src={require("../../../image/3.jpg").default} className="d-block w-100 carousel-img" alt="Slide 3" />
          </div>
        </div>
        {/* ... buttons ... */}
      </div>
    </div>
  );
}

export default Carousel;
